```python
import sys

def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    n, s = read_ints()
    a = list(read_ints())

    max_len = 0
    window_sum = 0
    left = 0

    for right in range(n):
        window_sum += a[right]

        while window_sum > s and left <= right:
            window_sum -= a[left]
            left += 1

        max_len = max(max_len, right - left + 1)

    print(max_len)

if __name__ == "__main__":
    main()
```

