import sys

def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    N, S = read_ints()
    A = list(read_ints())
    max_length = 0
    for i in range(N):
        current_sum = 0
        for j in range(i, N):
            current_sum += A[j]
            if current_sum <= S:
                max_length = max(max_length, j - i + 1)
    print(max_length)

if __name__ == "__main__":
    main()
