n, d = map(int, input().split())
a = list(map(int, input().split()))

cnt = defaultdict(int)
for x in a:
    for y in range(x - d, x + d + 1):
        cnt[y] += 1

ans = 0
for x in a:
    for y in range(x - d, x + d + 1):
        if y != x:
            ans += cnt[y]

print(ans // 2)
```

