import sys

def count_pairs(n, t, a):
    """Count the number of cheap pairs."""
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            if a[i] + a[j] <= t:
                count += 1
    return count

def main():
    """Read input and print the number of cheap pairs."""
    n, t = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    print(count_pairs(n, t, a))

if __name__ == "__main__":
    main()
