import sys

def main():
    n = int(input())
    a = list(map(int, input().split()))

    total_sum = 0
    for i in range(n):
        found = False
        for j in range(i-1, -1, -1):
            if a[j] < a[i]:
                total_sum += a[j]
                found = True
                break
        if not found:
            total_sum -= 1

    print(total_sum)

if __name__ == "__main__":
